     1→import { TransactionType, PointsDetailProps } from "./Models";
     2→import { PointsTransaction, AppliedFilters } from '../../services/models';
     3→import { DESCRIPTIONS } from './Models';
     4→import { PropsIconsNameCore } from '@semparar/design-system-app';
     5→
     6→export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     7→export type TagSubType = 'DRIVE_THRU' | 'PEDAGIO' | 'ESTACIONAMENTO' | 'ABASTECIMENTO' | 'LAVA_RAPIDO';
     8→
     9→
    10→export const getTransactionGainType = (transaction: PointsDetailProps['transaction']): TransactionGainType => {
    11→  const provider = transaction.details?.provider?.toLowerCase() || '';
    12→  
    13→  if (provider.includes('cashback')) {
    14→    return 'CASHBACK';
    15→  }
    16→  
    17→  const icon = transaction.icon?.toLowerCase() || '';
    18→  const description = transaction.description?.toLowerCase() || '';
    19→  
    20→  const tagIndicators = ['tag', 'pedágio', 'pedagio', 'estacionamento', 'abastecimento', 'abastece', 'drive', 'lava', 'rápido'];
    21→  
    22→  const isTag = tagIndicators.some(indicator => 
    23→    icon.includes(indicator) || 
    24→    description.includes(indicator) || 
    25→    provider.includes(indicator)
    26→  );
    27→  
    28→  return isTag ? 'TAG' : 'CARD';
    29→};
    30→
    31→export const getTagSubType = (transaction: PointsDetailProps['transaction']): TagSubType | null => {
    32→  const description = transaction.description?.toUpperCase() || '';
    33→  const provider = transaction.details?.provider?.toUpperCase() || '';
    34→  const extraInfo = transaction.details?.extraInfo?.toUpperCase() || '';
    35→  const searchText = `${description} ${provider} ${extraInfo}`;
    36→  
    37→  if (searchText.includes('DRIVE') || searchText.includes('DRIVE-THRU') || searchText.includes('DRIVE THRU')) {
    38→    return 'DRIVE_THRU';
    39→  }
    40→  if (searchText.includes('PEDÁGIO') || searchText.includes('PEDAGIO')) {
    41→    return 'PEDAGIO';
    42→  }
    43→  if (searchText.includes('ESTACIONAMENTO')) {
    44→    return 'ESTACIONAMENTO';
    45→  }
    46→  if (searchText.includes('ABASTECIMENTO') || searchText.includes('ABASTECE')) {
    47→    return 'ABASTECIMENTO';
    48→  }
    49→  if (searchText.includes('LAVA') && searchText.includes('RÁPIDO')) {
    50→    return 'LAVA_RAPIDO';
    51→  }
    52→  
    53→  return null;
    54→};
    55→
    56→export const getDetailScreenTitle = (gainType: TransactionGainType, transactionType?: TransactionType): string => {
    57→  if (gainType === 'CASHBACK' && transactionType === 'DEBIT') {
    58→    return 'Detalhes de uso';
    59→  }
    60→  if (gainType === 'CASHBACK') {
    61→    return 'Detalhes do Cashback';
    62→  }
    63→  return gainType === 'CARD' ? 'Detalhes da compra' : 'Detalhes da pontuação';
    64→};
    65→
    66→export const getVehicleInfo = (transaction: PointsDetailProps['transaction']): string | null => {
    67→  const fields = transaction.details?.fields || [];
    68→  
    69→  const marcaField = fields.find(f => f.label?.toLowerCase().includes('marca'));
    70→  const modeloField = fields.find(f => f.label?.toLowerCase().includes('modelo'));
    71→  const placaField = fields.find(f => f.label?.toLowerCase().includes('placa'));
    72→  
    73→  const marca = marcaField?.value || '';
    74→  const modelo = modeloField?.value || '';
    75→  const placa = placaField?.value || '';
